it("should keep a block stable (still life)", () => {
  const block: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
  const result = nextGeneration(block);
  expect(new Set(result.map(c => `${c[0]},${c[1]}`))).toEqual(
    new Set(block.map(c => `${c[0]},${c[1]}`))
  );
});
